def demonstrate_code_generation():
    """
    Demonstrates policy-as-code generation.
    """
    from models.cpm import CPMNormalizer
    
    print("=" * 70)
    print("POLICY-AS-CODE GENERATION DEMONSTRATION")
    print("=" * 70)
    
    # Sample resolved policies
    normalizer = CPMNormalizer()
    
    sample_rules = [
        {
            "rule_id": "GDPR_001",
            "subject": {"type": "processor", "roles": ["data_processor"]},
            "action": "export",
            "resource": {"type": "personal_data", "identifiers": ["export_api"]},
            "environment": {"consent_valid": True},
            "effect": "Permit",
            "obligations": ["require_audit_log", "require_encryption"],
        },
        {
            "rule_id": "PSD2_001",
            "subject": {"type": "customer", "roles": ["user", "account_holder"]},
            "action": "read",
            "resource": {"type": "account_data", "identifiers": ["balance_api", "transactions_api"]},
            "environment": {"authenticated": True, "sca_verified": True},
            "effect": "Permit",
        },
        {
            "rule_id": "SECURITY_001",
            "subject": {"type": "user", "roles": ["guest"]},
            "action": "read",
            "resource": {"type": "personal_data", "identifiers": []},
            "environment": {},
            "effect": "Deny",
        },
    ]
    
    cpm_rules = [
        normalizer.normalize_xacml_rule(sample_rules[0], "GDPR"),
        normalizer.normalize_xacml_rule(sample_rules[1], "PSD2"),
        normalizer.normalize_xacml_rule(sample_rules[2], "INTERNAL_SECURITY"),
    ]
    
    print("\n1. Rego Policy Generation:")
    print("-" * 50)
    
    rego_gen = RegoGenerator(package_name="policyguard.access")
    rego_policy = rego_gen.generate(cpm_rules, framework="PolicyGuard")
    
    print(rego_policy[:1500] + "...\n[truncated]")
    
    print("\n2. XACML Policy Generation:")
    print("-" * 50)
    
    xacml_gen = XACMLGenerator(policy_set_id="PolicyGuardResolvedPolicySet")
    xacml_policy = xacml_gen.generate(cpm_rules)
    
    print(xacml_policy[:1500] + "...\n[truncated]")
    
    print("\n3. Test Case Generation (from witness):")
    print("-" * 50)
    
    sample_witness = {
        "request": {
            "subject": "customer",
            "roles": ["user", "account_holder"],
            "action": "read",
            "resource": "balance_api",
            "resource_type": "account_data",
            "environment": {"authenticated": True}
        },
        "conflict": {
            "rule_i": "PSD2_001",
            "effect_i": "Permit",
            "rule_j": "SECURITY_001",
            "effect_j": "Deny"
        }
    }
    
    test_gen = TestCaseGenerator()
    opa_test = test_gen.generate_opa_test(sample_witness, "balance_access")
    print(opa_test)
    
    json_test = test_gen.generate_json_test_case(sample_witness)
    print("\nJSON Test Case:")
    print(json.dumps(json_test, indent=2))
    
    return rego_policy, xacml_policy


if __name__ == "__main__":
    demonstrate_code_generation()
